std::vector<float> loglinear_interp(const std::vector<float>& input, std::size_t count) {
    if (input.empty() || count == 0) return {};
    if (count == 1) return {input.front()};
    std::vector<double> reversed_log(input.size());
    for (std::size_t i=0;i<input.size();++i) reversed_log[i]=std::log(static_cast<double>(input[input.size()-1-i]));
    std::vector<float> out(count);
    for (std::size_t i=0;i<count;++i) {
        const double x=static_cast<double>(i)/static_cast<double>(count-1);
        const double pos=x*static_cast<double>(input.size()-1);
        const std::size_t lo=static_cast<std::size_t>(std::floor(pos));
        const std::size_t hi=std::min(input.size()-1,lo+1);
        const double f=pos-static_cast<double>(lo);
        out[count-1-i]=static_cast<float>(std::exp(reversed_log[lo]*(1.0-f)+reversed_log[hi]*f));
    }
    return out;
}
