std::vector<float> make_gits_sigmas(std::size_t steps, float coeff, float denoise) {
    if (steps < 2) throw Error("GITS scheduler requires at least two steps");
    if (!std::isfinite(coeff) || coeff < 0.80F || coeff > 1.50F) throw Error("GITS coeff must be in [0.80,1.50]");
    if (!std::isfinite(denoise) || denoise < 0.0F || denoise > 1.0F) throw Error("scheduler denoise must be in [0,1]");
    if (denoise <= 0.0F) return {};
    const int key=static_cast<int>(std::lround(static_cast<double>(coeff)*20.0))*5;
    if (std::abs(static_cast<double>(coeff) - static_cast<double>(key) / 100.0) > 1.0e-4) {
        throw Error("GITS coeff must use 0.05 increments");
    }
    const auto it=table().find(key);
    if (it==table().end()) throw Error("GITS coeff must use 0.05 increments");
    std::vector<float> sigmas;
    if (steps <= 20) sigmas=it->second.at(steps-2);
    else sigmas=loglinear_interp(it->second.back(), steps+1);
    const std::size_t total=static_cast<std::size_t>(std::nearbyint(static_cast<double>(steps)*denoise));
    if (total == 0) return {};
    if (total + 1 < sigmas.size()) sigmas.erase(sigmas.begin(), sigmas.end()-static_cast<std::ptrdiff_t>(total+1));
    if (!sigmas.empty()) sigmas.back()=0.0F;
    return sigmas;
}
